        return []
    if m == 1:
        target = pat_b[0]
        return [i for i in range(n) if text_b[i] == target]
    if text_b == pat_b:
        return [0]
    fail = [0] * m
    k = 0
    for i in range(1, m):
        while k > 0 and pat_b[k] != pat_b[i]:
            k = fail[k - 1]
        if pat_b[k] == pat_b[i]:
            k += 1
        fail[i] = k
    period = m - fail[m - 1]
    skip = [m] * 256
    for i in range(m - 1):
        skip[pat_b[i]] = m - 1 - i
    last = m - 1
    last_char = pat_b[last]
    first_char = pat_b[0]
    results = []
    append = results.append
    i = last
    while i < n:
        c = text_b[i]
        if c == last_char:
            start = i - last
            if text_b[start] == first_char and text_b[start:i + 1] == pat_b:
